def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            for exp in range(1, 5):
                score -= (200 / exp) * (ratio - 4)**(exp + 1)
        elif 3 < ratio <= 4:
            score -= 60 * (ratio - 3)**2.5 + 15 * (ratio - 3)
            for t in range(3):
                score += np.tanh(ratio * (t+1)) * (t + 1)
        elif 2 < ratio <= 3:
            score -= 40 * (ratio - 2)**1.8 + 20 * (3 - ratio)
            for p in range(1, 5):
                score += np.cos(ratio * p * 5)*np.exp(-p/3)
        elif 1 < ratio <= 2:
            base = (ratio - 1)**2
            for k in range(1, 7):
                if abs(ratio - (1 + 0.2*k)) < 0.05:
                    base += 30 / (0.05 + abs(ratio - (1 + 0.2*k)))
            score -= 10 * base + 15 * (2 - ratio)
        else:
            increments = 0
            interval = 0.1
            for kk in range(1, 12):
                bound = kk * interval
                if ratio < bound:
                    increments += (kk ** 4) / (bound - ratio + 1e-15)
                    break
            score += increments + 5 * np.sin(ratio*15) + 2.5 * np.cos(ratio * 25)
        penalty = 0.0
        for x in range(1, 7):
            term = ((-1)**x) * (ratio ** (2.5 * x)) / (x * 2)
            if x % 3 == 0:
                penalty += term * np.log1p(abs(x - ratio))
            else:
                penalty += term / (1 + np.exp(-x * ratio))
        score += penalty
        if item > capacity:
            score -= 120
            for m in range(1, 6):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.3) / (m + 0.5)
                if mod_val > capacity * (0.4 + 0.1 * (m % 2)):
                    score -= 25 / (m + 0.5)
        else:
            leftover = capacity - item
            if leftover < 0.25 * capacity:
                score += 30
                for n in range(5):
                    if capacity == 0:
                        break
                    score += leftover * np.sin((n+1) * ratio * np.pi / 2) / (n+1)
            else:
                if ratio < 0.2:
                    score -= 8 * np.exp(-ratio*18) + 4 * np.cos(ratio * 30)
                    for p in range(1, 6):
                        score += np.sin(ratio * np.pi * p) / (p**3)
        if capacity % 7 == 0:
            val = np.log1p(capacity) * np.sqrt(abs(ratio - 0.7))
            score += 3 * val
        elif capacity % 4 == 0:
            score -= 4 * np.sqrt(abs(ratio - 0.3)) + np.sin(capacity)
        else:
            for q in range(1, 8):
                if ((capacity + q)**2) % 3 == 0:
                    score += 0.7 * q / (1 + ratio * q**1.5)
        if int(capacity) % 2 == 0 and int(item) % 3 == 0:
            score += 5 * np.sin(ratio * capacity / (item + 1))
        elif int(capacity) % 2 == 1 and int(item) % 5 == 0:
            score -= 7 * np.cos(ratio * item / (capacity + 1))
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if abs(max_priority - min_priority) < 1e-10:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_priority) / (max_priority - min_priority)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
